      // A failed head stays queued and intentionally pauses drain until removed.
    }
  })();
}, [queue, isProcessing, sendMessage.isPending, optimisticMessage, activeSessionId, timelineId, sendNow]);

const handleNewSession = useCallback(async () => {
  if (!hasTimeline) {
    return;
  }
  setQueue([]);
  setOptimisticMessage(null);
  const session = await createSession.mutateAsync();
  setActiveSessionId(session.id);
  setDraft('');
}, [createSession, hasTimeline]);

const hasUnseenActivity = isProcessing && !isOpen;
if (!isToolPage) {
  return null;
}

let content: JSX.Element;

