    await sendMessage.mutateAsync({
      message: item.text,
      attachments: item.attachments,
    });
    clearGallerySelection();
  } catch (error) {
    setOptimisticMessage((prev) => (prev && prev.id === item.id ? null : prev));
    throw error;
  } finally {
    sendingRef.current = false;
  }
