    shotName: clip.shotName,
    shotSelectionClipCount: clip.shotSelectionClipCount,
    trackId: clip.trackId,
    at: clip.at,
    duration: clip.duration,
  }));

  if (rawText === undefined) setDraft('');
  const item: QueuedMessage = {
    id: createMessageId(),
    text,
    attachments,
  };

