    sendingRef.current
    || isProcessing
    || sendMessage.isPending
    || optimisticMessage
    || queue.length > 0
  ) {
    setQueue((prev) => [...prev, item]);
    return;
  }

  await sendNow(item);
}, [activeSessionId, clips, draft, isProcessing, optimisticMessage, queue.length, sendMessage.isPending, sendNow, timelineId]);

